int deleteDigit(int n, int i)
{
    int result = 0, remain = 1;
    while (n != 0)
    {
        if (n % 10 != i) // i gonna be digit num
        {
            result += (n % 10) * remain;
            remain = remain * 10;
        }
        n /= 10;
    }
    return result;
}

int largestPalin(int n)
{
    int largest = 0;
    for (int i = 0; i <= 9; i++)
    {
        int temp = deleteDigit(n, i);
        if (isPalin(temp) == true && temp > largest)
        {
            largest = temp;
        }
    }
    if (largest == 0)
        return -1;
    return largest;
}
